import { useEffect, useRef } from 'react';
import './AmbientLayer.css';

const AmbientLayer = () => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    let width = canvas.width = window.innerWidth;
    let height = canvas.height = window.innerHeight;

    let particles = [];
    const numParticles = Math.min(window.innerWidth / 15, 100); // Responsive amount of particles, cap at 100 for perf.

    // Mouse interaction tracking
    let mouse = {
      x: width / 2,
      y: height / 2,
      radius: 150 // Radius of cursor influence
    };

    const handleMouseMove = (e) => {
      mouse.x = e.clientX;
      mouse.y = e.clientY;
    };

    window.addEventListener('mousemove', handleMouseMove, { passive: true });

    const handleResize = () => {
      width = canvas.width = window.innerWidth;
      height = canvas.height = window.innerHeight;
      initParticles();
    };

    window.addEventListener('resize', handleResize);

    class Particle {
      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.size = Math.random() * 1.5 + 0.5; // Very subtle size
        this.baseX = this.x;
        this.baseY = this.y;
        this.density = (Math.random() * 30) + 1;
        this.velocity = {
          x: (Math.random() - 0.5) * 0.5,
          y: (Math.random() - 0.5) * 0.5
        };
      }

      draw() {
        ctx.fillStyle = 'rgba(242, 240, 235, 0.15)'; // --color-text slightly opaque
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.closePath();
        ctx.fill();
      }

      update() {
        // Natural drifting
        this.x += this.velocity.x;
        this.y += this.velocity.y;

        // Wrap around screen
        if (this.x < 0) this.x = width;
        if (this.x > width) this.x = 0;
        if (this.y < 0) this.y = height;
        if (this.y > height) this.y = 0;

        // Mouse Repulsion logic
        let dx = mouse.x - this.x;
        let dy = mouse.y - this.y;
        let distance = Math.sqrt(dx * dx + dy * dy);
        let forceDirectionX = dx / distance;
        let forceDirectionY = dy / distance;

        // Push particles away
        let force = (mouse.radius - distance) / mouse.radius;
        let directionX = (forceDirectionX * force * this.density) * -1; // -1 for repel
        let directionY = (forceDirectionY * force * this.density) * -1;

        if (distance < mouse.radius) {
          this.x += directionX;
          this.y += directionY;
        } else {
          // Slow return to normal velocity
          if (this.x !== this.baseX) {
            let dxReturn = this.x - this.baseX;
            this.x -= dxReturn / 100; // Slow spring rate
          }
          if (this.y !== this.baseY) {
            let dyReturn = this.y - this.baseY;
            this.y -= dyReturn / 100;
          }
        }
      }
    }

    function initParticles() {
      particles = [];
      for (let i = 0; i < numParticles; i++) {
        particles.push(new Particle());
      }
    }

    function animate() {
      ctx.clearRect(0, 0, width, height);
      for (let i = 0; i < particles.length; i++) {
        particles[i].draw();
        particles[i].update();
      }

      // Draw faint connective lines
      connect();
      requestAnimationFrame(animate);
    }

    function connect() {
      let opacityValue = 1;
      for (let a = 0; a < particles.length; a++) {
        for (let b = a; b < particles.length; b++) {
          let distance = ((particles[a].x - particles[b].x) * (particles[a].x - particles[b].x))
            + ((particles[a].y - particles[b].y) * (particles[a].y - particles[b].y));

          if (distance < (width / 10) * (height / 10)) {
            opacityValue = 1 - (distance / 20000);
            ctx.strokeStyle = `rgba(126, 124, 119, ${opacityValue * 0.15})`; // --color-muted slightly opaque
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(particles[a].x, particles[a].y);
            ctx.lineTo(particles[b].x, particles[b].y);
            ctx.stroke();
          }
        }
      }
    }

    initParticles();
    animate();

    return () => {
      window.removeEventListener('resize', handleResize);
      window.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  return <canvas ref={canvasRef} className="ambient-layer-canvas" />;
};

export default AmbientLayer;

import React, { useRef, useState, useEffect } from 'react';
import { motion, useMotionValue, useSpring } from 'framer-motion';

const MagneticElement = ({ children, strength = 0.5, className = '', tag = 'div', style = {} }) => {
  const ref = useRef(null);
  const [isHovered, setIsHovered] = useState(false);

  // Motion values
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  // Spring config for smooth push/pull
  const springConfig = { damping: 15, stiffness: 150, mass: 0.1 };
  const springX = useSpring(x, springConfig);
  const springY = useSpring(y, springConfig);

  const handleMouseMove = (e) => {
    if (!ref.current) return;

    // Get mouse coordinates
    let clientX = e.clientX;
    let clientY = e.clientY;

    // Fallback for touch
    if (e.touches && e.touches.length > 0) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    }

    const { left, top, width, height } = ref.current.getBoundingClientRect();

    // Find center of element
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    // Calculate distance to move (pull towards cursor based on strength)
    const moveX = (clientX - centerX) * strength;
    const moveY = (clientY - centerY) * strength;

    x.set(moveX);
    y.set(moveY);
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
    x.set(0);
    y.set(0);
  };

  const handleMouseEnter = () => {
    setIsHovered(true);
  };

  // We wrap the children in a Framer Motion component
  const MotionComponent = motion[tag] || motion.div;

  return (
    <MotionComponent
      ref={ref}
      className={`magnetic-wrapper ${className}`}
      onMouseMove={handleMouseMove}
      onTouchMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      onTouchEnd={handleMouseLeave}
      onMouseEnter={handleMouseEnter}
      style={{
        ...style,
        x: springX,
        y: springY,
        display: 'inline-block' // Ensures transforms happen cleanly
      }}
    >
      {React.cloneElement(children, {
        // Optionally pass hover state down if children need it
        'data-magnetic-hover': isHovered
      })}
    </MotionComponent>
  );
};

export default MagneticElement;

